sp_theme.css_variables:
/* CSS Variables for Bootstrap

2.7.0 | 2021-10-26 | mmcc | STRY0110472 - Stretch- 508 Compliant- Delete Buttons- (ALL Red buttons)
  Change var tasker-color-red to #B71C1C was #E32921
  Change var banner-count-bg to use var tasker-color-red
  Change var brand-danger to use var tasker-color-red
  Added $required-info-bg to control the background color of Required information warnings

*/

$required-info-bg: $tasker-color-red;
$brand-danger: $tasker-color-red;

/* Banner Notification & Danger Dots */
//--------------------------------------------------------
$banner-count-bg: 				$tasker-color-red !default; //danger
$banner-count-text: 			white !default;

/* To get service status messages consistent with brand colors */
//------------------------------------------------------------------------------------------------------------------------
$primary: 						$brand-primary;
$warning: 						$brand-warning;
$success: 						$brand-success;
$info: 							$brand-info;
$danger: 						$brand-danger;
$input-border-placeholder: 		white;


/* To get color boxes and count colors consistent with brand colors */
//------------------------------------------------------------------------------------------------------------------------
$brand-primary-text:			white !default;
$brand-warning-text:			#434343 !default;
$brand-success-text:			#434343 !default;
$brand-info-text:				white !default;
$brand-danger-text:				white !default;

/*
2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
  Added Tasker colors section
*/
/* Tasker colors */
$tasker-color-blue-dark-35363a: #35363A; /* is a dark shade of blue, rgb(53, 54, 58), Tasker Delete Task task-name */
$tasker-color-blue-magenta: #736ac6; /* is a shade of blue-magenta, rgb(115, 106, 198), Tasker Flow In Review chevron */
$tasker-color-brown-red: #ff9800; /* is a shade of brown, rgb(255, 152, 0), Tasker Modal - Delete Task, Warning */
$tasker-color-cyan: #37c1c3; /* is a shade of cyan, rgb(55, 193, 195), Tasker Flow Completed chevron */
$tasker-color-cyan-blue-0087d2 : #0087d2 ; /* is a shade of cyan-blue, rgb(0, 135, 210), Tasker Delete Task subtasks also deleted  */
$tasker-color-cyan-blue-2174ab: #2174ab; /* is a medium dark shade of cyan-blue, rgb(33, 116, 171), Classification Banner Official */
$tasker-color-cyan-blue-2e3c54: #2e3c54; /* is a medium dark shade of cyan-blue, rgb(46, 60, 84), Tasker Flow Work in progress chevron */
$tasker-color-cyan-blue-427A93: #427A93; /* is a shade of cyan, rgb(66, 122, 147), Tasker Flow Assigned chevron */
$tasker-color-gray-very-light: #dddddd; /* or #ddd is a very light shade of gray, rgb(221, 221, 221), Tasker Flow Disabled chevron */
$tasker-color-gray: #6b6b6b; /* is a shade of gray, rgb(107, 107, 107), Tasker Flow Waiting chevron */
$tasker-color-green-cyan-blue: #407d6f; /* is a medium dark shade of green-cyan (more blue), Classification Banner Restricted */
$tasker-color-green-cyan: #44835e; /* is a medium dark shade of green-cyan (less blue), Classification Banner Unclassified */
$tasker-color-green-medium-light: #a0d468; /* is a medium light shade of green, rgb(160,212,104), Tasker Flow */
$tasker-color-red-orange: #795548; /* is a medium dark shade of red-orange, Classification Banner Protected */
$tasker-color-red: #B71C1C; /* is a shade of red, Classification Banner Secret, Tasker Flow Rejected chevron */
$tasker-color-yellow-blue: #f6c716; /* is a shade of yellow, rgb(246, 199, 22), Tasker Flow Unassigned chevron */
$tasker-color-yellow: #ffcc00; /* tangerine yellow, rgb(255, 207, 0), Classification Banner Top Secret */

/* Delete Task Prompt */
$tasker-svg-warning64-fill: $tasker-color-brown-red;
$tasker-delete-prompt-task-name: $tasker-color-blue-dark-35363a;
$tasker-delete-prompt-subtasks-also-deleted : $tasker-color-cyan-blue-0087d2;
$tasker-modal-prompt-standard-text-color: $tasker-color-blue-dark-35363a;
/*
2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
Added Tasker Restricted Group Banner and Badge section
*/
/* Tasker Restricted Group Banner and Badge */
$restricted-group-border-color: white;
$restricted-group-primary-text: $brand-primary-text;

$restricted-group-banner-bg: $tasker-color-red;
$restricted-group-banner-text: $restricted-group-primary-text;

$restricted-group-badge-bg:$tasker-color-red;
$restricted-group-badge-text: $restricted-group-primary-text;

/*
2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
Added Tasker Classification Banner section
*/
/* Tasker Classification Banner and Badge */
$classification-border-color: white;
$classification-primary-text: $brand-primary-text;
$classification-top-secret-text: $brand-success-text;

$classification-unclassified-bg: $tasker-color-green-cyan;
$classification-unclassified-text: $classification-primary-text;

$classification-official-bg: $tasker-color-cyan-blue-2174ab;
$classification-official-text: $classification-primary-text;

$classification-protected-bg: $tasker-color-red-orange;
$classification-protected-text: $classification-primary-text;

$classification-restricted-bg: $tasker-color-green-cyan-blue;
$classification-restricted-text: $classification-primary-text;

$classification-secret-bg: $tasker-color-red;
$classification-secret-text: $classification-primary-text;

$classification-top-secret-bg: $tasker-color-yellow;
$classification-top-secret-text: $classification-top-secret-text;


/*
2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
Added state primary and success text var's, replaced hex colors with var's
2.7.0 | 2021-08-20 | mmcc | STRY0107808 - DIA-Scheduled Draft- Tree View Widget- Add Draft State
Added CSS variables for Draft; $state-draft-bg and $state-draft-text
*/
/* Tasker States */
//--------------------------------------------------------
$state-primary-text: $brand-primary-text; //white
$state-success-text: $brand-success-text; //#434343

$state-disabled-bg: 			$tasker-color-gray-very-light !default;
$state-disabled-text: 			$state-success-text !default;

$state-new-bg: 					white !default;
$state-new-text: 				$state-success-text !default;

$state-draft-bg: $tasker-color-gray !default;
$state-draft-text: $state-primary-text !default;

$state-waiting-bg: 				$tasker-color-gray !default;
$state-waiting-text: 			$state-primary-text !default;

$state-unassigned-bg: 			$tasker-color-yellow-blue !default; //warning
$state-unassigned-text: 		$state-success-text !default;

$state-assigned-bg: 			$tasker-color-cyan-blue-427A93 !default;
$state-assigned-text: 			$state-primary-text !default;

$state-accepted-bg: 			$tasker-color-green-medium-light !default;
$state-accepted-text: 			$state-success-text !default;

$state-rejected-bg: 			$tasker-color-red !default; //danger 
$state-rejected-text: 			$state-primary-text !default;

$state-workinprogress-bg: 		$tasker-color-cyan-blue-2e3c54 !default; //primary
$state-workinprogress-text: 	$state-primary-text !default;

$state-workscheduled-bg: 		$tasker-color-cyan-blue-2e3c54 !default; //primary
$state-workscheduled-text: 		$state-primary-text !default;

$state-inreview-bg: 			$tasker-color-blue-magenta !default; //info
$state-inreview-text: 			$state-primary-text !default;

$state-rework-bg: 				$tasker-color-cyan-blue-2e3c54 !default; //primary
$state-rework-text: 			$state-primary-text !default;

$state-completed-bg: 			$tasker-color-cyan !default; //success
$state-completed-text: 			$state-success-text !default;

$state-closedincomplete-bg: 	$tasker-color-cyan !default; //success
$state-closedincomplete-text:	$state-success-text !default;

$state-cancelled-bg: 			$tasker-color-cyan !default; //success
$state-cancelled-text: 			$state-success-text !default;

/* Icons overrrides on Summary Card */
//--------------------------------------------------------
$icon-default-bg: 				#434343;


/* Tasker Data Table Selected Row */
//--------------------------------------------------------
$taskerdatatable-selected-row-bg: #B5DDE5; //#767676;
$taskerdatatable-selected-row-text:	#434343; //#fff;

/* Task List View */
//--------------------------------------------------------
$tasklistview-selected-border-right-bg: #ADD8E6;
$tasklistview-selected-bg: 		white;
$tasklistview-bg: 				#F5F5F5;


/* Alert overrides */
//--------------------------------------------------------
$state-danger-bg: lighten(saturate(adjust-hue($brand-danger, 354), 42.52%), 42.94);
$state-danger-border: $brand-danger;
$state-danger-text: darken(saturate(adjust-hue($brand-danger, 2), 1.25%), 25.10);
//$state-info-bg: lighten(desaturate($brand-info, 3.27%), 19.02);
//$state-info-border: $brand-info;
$state-info-text: #457e92; //darken(desaturate(adjust-hue($brand-info, 1), 2.75%), 41.57);
$state-success-bg: lighten(saturate($brand-success, 3.67%), 28.24);
$state-success-border: $brand-success;
$state-success-text: darken(desaturate(adjust-hue($brand-success, 3), 15.64%), 34.31);
$state-warning-bg: lighten(saturate(adjust-hue($brand-warning, -3), 17.70%), 29.61);
$state-warning-border: $brand-warning;
$state-warning-text: darken(desaturate(adjust-hue($brand-warning, -4), 20.32%), 44.31);

$alert-danger-bg: $state-danger-bg;
$alert-danger-border: $state-danger-border;
$alert-danger-text: $state-danger-text;
$alert-info-bg: white;
$alert-info-border: #5bc0de;
$alert-info-text: #407e91;
$alert-success-bg: $state-success-bg;
$alert-success-border: $state-success-border;
$alert-success-text: $state-success-text;
$alert-warning-bg: $state-warning-bg;
$alert-warning-border: $state-warning-border;
$alert-warning-text: $state-warning-text;


/* Default */
//------------------------------------------------------------------------------------------------------------------------
$sp-logo-margin-x: 				15px !default;
$sp-tagline-color: 				$text-color !default;
$navbar-inverse-bg: 			#3a3f51 !default;
$navbar-inverse-link-color: 	#bdc0c4 !default;
$navbar-inverse-link-hover-color: #ffffff !default;
$body-bg: 						#f0f3f4 !default;
$dropdown-link-disabled-color: 	#ccc;

/*
2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
  seems this shows up with an emtpy  selector block, let's comment out
@media screen and (min-width: 768px) {
	.navbar-right .dropdown-menu {
		left: -10% !default;
		right: auto !default;
	}
}
*/

/* 508 */
//------------------------------------------------------------------------------------------------------------------------
/* 
2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
was #434343, changed to use variable for brand success text
*/
$accessible-placeholder-gray: 	$brand-success-text; //updated

/* 
2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
ServiceNow > Settings > Accessibility > Accessibility enabled > sets accessibility="true" in <body> tag
Syntax mouse over link should be "a:hover { color: pink; }"; therefore the below hover and focus should never work
.sp-announcement-root selector does not get added to F12 Elements; not working
uib-rating, UI Bootstrap Directive Rating, does not seem to work
input placeholder for the 3 browsers does not seem to work
Therefore, Comment out the "[accessibility="true"] {" block
*/
/*
[accessibility="true"] {
	a {
		&:hover {
			text-decoration: underline !default;
		}
		&:focus {
			text-decoration: underline !default;
		}
	}
	.sp-announcement-root {
		a {
			text-decoration: underline !default;
		}
	}
	[uib-rating] {
		.glyphicon-star {
			color: black !default;
		}
	}
	input::-webkit-input-placeholder {
		color: $accessible-placeholder-gray !default;
	}
	input::-moz-placeholder {
		color: $accessible-placeholder-gray !default;
	}
	input:-ms-input-placeholder {
		color: $accessible-placeholder-gray !default;
	}
}
*/
